mapper.update:
UPDATE questions


        title = #{title},


        difficulty = #{difficulty},

    update_time = #{updateTime},
    update_user = #{updateUser}

WHERE id = #{id}

mapper.select:
SELECT q.id, q.title, q.difficulty, q.create_time, u.name AS create_name FROM questions q LEFT JOIN user u ON q.create_user = u.id
AND q.title LIKE CONCAT('%', #{title}, '%')
AND q.difficulty = #{difficulty}
AND q.create_user = #{createId}
AND q.create_user IN ( SELECT u.id FROM user u WHERE u.name LIKE CONCAT('%', #{name}, '%') )
AND q.id IN ( SELECT DISTINCT qk.question_id FROM question_knowledge qk WHERE qk.knowledge_id IN
#{kid}
)
ORDER BY q.id DESC
